import{_ as t,c as o,o as i,a1 as r}from"./chunks/framework.DDNAyvCW.js";const a="/assets/files.7FAUAaza.png",u=JSON.parse('{"title":"File Management","description":"","frontmatter":{},"headers":[],"relativePath":"docs/manage/files/index.md","filePath":"docs/manage/files/index.md"}'),n={name:"docs/manage/files/index.md"};function s(l,e,d,h,c,g){return i(),o("div",null,e[0]||(e[0]=[r('<h1 id="file-management" tabindex="-1">File Management <a class="header-anchor" href="#file-management" aria-label="Permalink to &quot;File Management&quot;">​</a></h1><p>Browse, edit, and transfer files on remote servers through Chaterm&#39;s built-in SFTP-based file manager.</p><p><img src="'+a+'" alt=""></p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before using File Management, make sure:</p><ul><li>You have an <strong>active SSH connection</strong> to the target host. If you are not connected yet, see <a href="/docs/hosts/connect">Connect to a Host</a>.</li><li>The remote server has <strong>SFTP enabled</strong>. Most OpenSSH installations enable SFTP by default, but some hardened servers disable it.</li></ul><div class="warning custom-block"><p class="custom-block-title">SFTP Required</p><p>File Management relies entirely on the server&#39;s SFTP subsystem. If SFTP is not enabled on the remote server, browsing, editing, and transferring files will not work. Ask your server administrator to enable the SFTP subsystem if you see connection errors in File Management.</p></div><h2 id="browsing-files" tabindex="-1">Browsing Files <a class="header-anchor" href="#browsing-files" aria-label="Permalink to &quot;Browsing Files&quot;">​</a></h2><ol><li>Click <strong>File Management</strong> in the left sidebar.</li><li>Chaterm displays the remote file tree for the currently connected host.</li><li>Click a <strong>folder</strong> to expand or collapse its contents.</li><li><strong>Right-click</strong> a directory and select <strong>Refresh</strong> to reload its file list.</li><li>Use the <strong>search bar</strong> at the top of the file tree to find a file or directory by name.</li></ol><h2 id="editing-files" tabindex="-1">Editing Files <a class="header-anchor" href="#editing-files" aria-label="Permalink to &quot;Editing Files&quot;">​</a></h2><ol><li><strong>Double-click</strong> a file in the file tree to open it in the built-in editor.</li><li>Edit the file content. The editor provides syntax highlighting that is detected automatically from the file type.</li><li>Click the <strong>Save</strong> button (or use the keyboard shortcut) to write your changes back to the remote server.</li></ol><p>The editor offers a modern, IDE-like experience with multi-language syntax highlighting.</p><h2 id="uploading-files" tabindex="-1">Uploading Files <a class="header-anchor" href="#uploading-files" aria-label="Permalink to &quot;Uploading Files&quot;">​</a></h2><ol><li>In the file tree, navigate to the <strong>target directory</strong> where you want to place the file.</li><li>Click the <strong>Upload</strong> button, or drag one or more local files directly into the file tree area.</li><li>Select the files or folders you want to upload (if you used the button).</li><li>A progress indicator shows the transfer speed and percentage. Wait for the upload to finish.</li></ol><h2 id="downloading-files" tabindex="-1">Downloading Files <a class="header-anchor" href="#downloading-files" aria-label="Permalink to &quot;Downloading Files&quot;">​</a></h2><ol><li>In the file tree, locate the file or folder you want to download.</li><li><strong>Right-click</strong> the item and select <strong>Download</strong>, or select the item and click the <strong>Download</strong> button.</li><li>Choose a local save location when prompted.</li><li>Wait for the download to complete. The progress indicator shows transfer status.</li></ol><h2 id="file-operations" tabindex="-1">File Operations <a class="header-anchor" href="#file-operations" aria-label="Permalink to &quot;File Operations&quot;">​</a></h2><p>You can perform the following operations by right-clicking a file or folder in the file tree:</p><table tabindex="0"><thead><tr><th>Operation</th><th>Description</th></tr></thead><tbody><tr><td><strong>Rename</strong></td><td>Change the name of a file or folder.</td></tr><tr><td><strong>Permissions</strong></td><td>Modify file permissions (<code>chmod</code>). Enter the new mode (e.g., <code>755</code>) in the dialog.</td></tr><tr><td><strong>Copy</strong></td><td>Copy a file or folder to another location on the server.</td></tr><tr><td><strong>Move</strong></td><td>Move a file or folder to a different directory on the server.</td></tr><tr><td><strong>Delete</strong></td><td>Permanently remove a file or folder. This action is irreversible -- use with caution.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li><strong>Large files</strong> may take a significant amount of time to transfer. Keep the connection open and avoid navigating away until the transfer completes.</li><li><strong>System files</strong> may require elevated permissions. If you cannot edit or delete a file, check that your user account has the necessary access.</li><li><strong>Back up important files</strong> before making edits, especially on production servers.</li></ul>',21)]))}const m=t(n,[["render",s]]);export{u as __pageData,m as default};
